  bool get isDelivered => status == OrderStatus.delivered;

  int get itemCount {
    return items.fold(0, (sum, item) => sum + item.quantity);
  }

  Order copyWith({
    OrderStatus? status,
    List<OrderItem>? items,
  }) {
    return Order(
      id: id,
      items: items ?? this.items,
      createdAt: createdAt,
      status: status ?? this.status,
      subtotal: subtotal,
      tax: tax,
      shipping: shipping,
    );
  }
}

class OrderItem {
  final String productId;
